public interface ICommand { void Execute(); void Undo(); }

public class AddItemCommand : ICommand {
    private readonly ShoppingCart _cart;
    private readonly CartItem _item;
    public AddItemCommand(ShoppingCart cart, CartItem item) =>
        (_cart, _item) = (cart, item);
    public void Execute() => _cart.Add(_item);
    public void Undo()    => _cart.Remove(_item); // knows how to reverse itself
}

// Invoker: execute and track for undo
var history = new Stack<ICommand>();
var cmd = new AddItemCommand(cart, item);
cmd.Execute(); history.Push(cmd);
history.Pop().Undo(); // remove the last added item

public abstract class ReportExporter {
    // Template method -- sequence is LOCKED, sealed prevents override
    public sealed void Export(ReportData data, string path) {
        var filtered  = Filter(data);    // varies per format
        var formatted = Format(filtered); // varies per format
        Validate(formatted);             // shared default (hook)
        Write(formatted, path);          // varies per format
    }
    protected abstract ReportData    Filter(ReportData d);
    protected abstract string        Format(ReportData d);
    protected virtual  void          Validate(string content) { } // hook
    protected abstract void          Write(string content, string path);
}
public class CsvExporter : ReportExporter {
    protected override ReportData Filter(ReportData d)  => /* remove nulls */ d;
    protected override string     Format(ReportData d)  => /* CSV lines */ "";
    protected override void       Write(string c, string p) => File.WriteAllText(p, c);
}

// ASP.NET Core middleware = textbook Chain of Responsibility
app.Use(async (ctx, next) => {
    // Authentication link
    if (!ctx.User.Identity!.IsAuthenticated) {
        ctx.Response.StatusCode = 401;
        return; // SHORT-CIRCUIT: do not call next()
    }
    await next(); // PASS: continue to the next handler
});

